local function file_serve()
    local filename = ngx.var.arg_filename
    if not filename then
        return ngx.redirect("/")
    end

    local filepath = "./files/" .. filename
    local file, err = io.open(filepath, "rb")
    if not file then
        ngx.say("File not found: ", filepath)
        return ngx.exit(404)
    end

