            ["index.htm"] = "text/html";
            ["index.shtml"] = "text/html";
            ["default.html"] = "text/html";
            ["default.htm"] = "text/html";
            ["default.shtml"] = "text/html";
            ["error.html"] = "text/html";
            ["error.htm"] = "text/html";
            ["error.shtml"] = "text/html";
            ["index.php"] = "application/x-httpd-php";
        }

        local extension = filename:match("%.(%w+)$") or ''
        return mime_types[filename] or 'application/octet-stream'
    end

    ngx.say("Content-Type:", get_mime(filename), "\n\n", content)
end

